import React, { useEffect } from 'react';
import { NavigationContainer, useNavigation } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';
import { Linking } from 'react-native';
import ProfileScreen from './ProfileScreen';
import PaymentScreen from './PaymentScreen';

const Stack = createStackNavigator();

const App = () => {
  const navigation = useNavigation();

  useEffect(() => {
    const handleDeepLink = ({ url }) => {
      if (url) {
        const route = parseUrl(url);
        if (route) {
          navigation.navigate(route.name, route.params);
        }
      }
    };

    const parseUrl = (url) => {
      const matched = url.match(/myapp:\/\/(\w+)\/(.+)/);
      if (matched) {
        const [, path, idOrSlug] = matched;
        switch (path) {
          case 'profile':
            return { name: 'Profile', params: { userId: idOrSlug } };
          case 'payment':
            if (idOrSlug === 'confirm') {
              return { name: 'PaymentConfirm' };
            }
            break;
          default:
            return null;
        }
      }
      return null;
    };

    const linkingListener = Linking.addEventListener('url', handleDeepLink);
    Linking.getInitialURL().then((url) => url && handleDeepLink({ url }));

    return () => {
      linkingListener.remove();
    };
  }, [navigation]);

  return (
    <NavigationContainer>
      <Stack.Navigator>
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

export default App;